package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnPostReportProxy struct {
	automation.UnimplementedOnPostReportServer
	client automation.OnPostReportClient
}

func init() {
	proxyutil.Register(&automation.OnPostReport_ServiceDesc, NewOnPostReportProxy)
}
func NewOnPostReportProxy(cc grpc.ClientConnInterface) automation.OnPostReportServer {
	return &OnPostReportProxy{client: automation.NewOnPostReportClient(cc)}
}
func (p *OnPostReportProxy) OnPostReport(ctx context.Context, in *events.PostReport) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.PostReport, automation.HandlerResult](p.client.OnPostReport)(ctx, in)
}
